t.script:
document.addEventListener('DOMContentLoaded', function () {
// Scroll-triggered animations
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -100px 0px'
};

const observer = new IntersectionObserver(function(entries) {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('animate-loaded');
}
});
}, observerOptions);

// Observe all sections
document.querySelectorAll('.careers-hero, .why-section, .openings-section, .process-section,
.life-section, .cta-section').forEach(section => {
observer.observe(section);
});

// Job search functionality
var searchInput = document.querySelector('.prq-job-search');
var searchBtn = document.querySelector('.prq-search-btn');
var jobCards = document.querySelectorAll('.prq-job-card');

function filterJobs(query) {
query = (query || '').toLowerCase();
jobCards.forEach(function (card) {
var title = (card.querySelector('.prq-job-title') || {}).textContent || '';
var company = (card.querySelector('.prq-job-company') || {}).textContent || '';
var meta = (card.querySelector('.job-meta') || {}).textContent || '';
var combined = (title + ' ' + company + ' ' + meta).toLowerCase();
card.style.display = combined.indexOf(query) !== -1 ? 'block' : 'none';
});
}

if (searchInput) {
searchInput.addEventListener('input', function (e) {
filterJobs(e.target.value);
});
}
if (searchBtn) {
searchBtn.addEventListener('click', function () {
filterJobs(searchInput ? searchInput.value : '');
});
}

// Smooth hover effects for cards
document.querySelectorAll('.stat-card, .benefit-card, .job-card, .life-card, .step').forEach(card => {
card.addEventListener('mouseenter', function() {
this.style.transform = 'translateY(-15px) scale(1.02)';
});
card.addEventListener('mouseleave', function() {
this.style.transform = 'translateY(0) scale(1)';
});
});

// Hero parallax effect
window.addEventListener('scroll', function() {
const scrolled = window.pageYOffset;
const hero = document.querySelector('.careers-hero');
if (hero) {
hero.style.transform = `translateY(${scrolled * 0.4}px)`;
}
});

// Staggered job card animation
const jobCardsList = document.querySelectorAll('.prq-job-card');
jobCardsList.forEach((card, index) => {
card.style.animationDelay = `${index * 0.15}s`;
});
});

document.addEventListener('DOMContentLoaded', function () {
// Scroll animations
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -100px 0px'
};
const observer = new IntersectionObserver(function(entries) {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('animate-loaded');
}
});
}, observerOptions);

document.querySelectorAll('.job-detail-hero, .job-card-detail, .job-description-section,
.apply-card').forEach(el => {
observer.observe(el);
});

// Error popup
var errorClose = document.getElementById('errorClose');
if (errorClose) {
errorClose.addEventListener('click', function () {
document.getElementById('errorPopup').remove();
});
}

// Form submission
var form = document.querySelector('.form-grid');
if (form) {
form.addEventListener('submit', function () {
var btn = this.querySelector('.submit-btn');
if (btn) {
btn.innerHTML = ' Submitting...';
btn.disabled = true;
}
});
}

// Location suggestions
var locationInput = document.querySelector('input[name="partner_location"]');
var suggestionsList = document.getElementById('locationSuggestions');
if (locationInput && suggestionsList) {
var timer = null;

suggestionsList.addEventListener('click', function(ev) {
var target = ev.target.closest('.suggestion-item');
if (target) {
locationInput.value = target.dataset.value || target.textContent;
suggestionsList.innerHTML = '';
}
});

locationInput.addEventListener('input', function() {
var term = this.value.trim();
clearTimeout(timer);
if (term.length
<
2) {
suggestionsList.innerHTML = '';
return;
}
timer = setTimeout(() => {
fetch('/jobs/location_suggest', {
method: 'POST',
headers: {'Content-Type': 'application/json'},
body: JSON.stringify({
jsonrpc: '2.0',
method: 'call',
params: {term: term},
id: Date.now()
})
})
.then(res => res.json())
.then(data => {
var suggestions = data.result || [];
suggestionsList.innerHTML = suggestions.map(item => {
var safe = String(item).replace(/"/g, '"');
return `${item}`;
}).join('');
})
.catch(() => { suggestionsList.innerHTML = ''; });
}, 300);
});

locationInput.addEventListener('blur', () => {
setTimeout(() => { suggestionsList.innerHTML = ''; }, 200);
});
}

// Hero parallax
window.addEventListener('scroll', () => {
const scrolled = window.pageYOffset;
const hero = document.querySelector('.job-detail-hero');
if (hero) {
hero.style.transform = `translateY(${scrolled * 0.3}px)`;
}
});

// Enhanced hover effects
document.querySelectorAll('.info-card, .job-card-detail, .job-description-section').forEach(card => {
card.addEventListener('mouseenter', function() {
this.style.transform = 'translateY(-15px) scale(1.02)';
});
card.addEventListener('mouseleave', function() {
this.style.transform = 'translateY(0) scale(1)';
});
});
});

document.addEventListener('DOMContentLoaded', function () {
// Scroll-triggered animations
const observerOptions = {
threshold: 0.1,
rootMargin: '0px 0px -50px 0px'
};

const observer = new IntersectionObserver(function(entries) {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('animate-loaded');
}
});
}, observerOptions);

observer.observe(document.querySelector('.prq-success-container'));

// Particle system
var particlesContainer = document.getElementById('prqParticles');
if (!particlesContainer) return;

function createParticles() {
var colors = ['#d89a2b', '#e5b55b', '#f8e8b0'];
for (var i = 0; i
<
25; i++) {
var p = document.createElement('div');
var color = colors[Math.floor(Math.random() * colors.length)];
p.className = 'prq-particle';
p.style.background = color;
p.style.left = (20 + Math.random() * 60) + '%';
p.style.top = (20 + Math.random() * 40) + '%';
p.style.setProperty('--dx', (-150 + Math.random() * 300) + 'px');
p.style.setProperty('--dy', (-150 + Math.random() * 300) + 'px');
p.style.animationDuration = (1.5 + Math.random() * 1) + 's';
particlesContainer.appendChild(p);

// Remove particle after animation
(function (particle) {
setTimeout(function () {
if (particle.parentNode) particle.remove();
}, 2500);
})(p);
}
}

// Initial burst + continuous particles
createParticles();
setInterval(createParticles, 3500);

// Smooth hover effects
document.querySelectorAll('.prq-success-card, .details, .primary-btn, .secondary-btn').forEach(el => {
el.addEventListener('mouseenter', function() {
this.style.transform = 'translateY(-8px) scale(1.02)';
});
el.addEventListener('mouseleave', function() {
this.style.transform = 'translateY(0) scale(1)';
});
});

// Floating animation for checkmark
const checkmark = document.querySelector('.checkmark');
if (checkmark) {
checkmark.classList.add('animate-float');
}
});
